import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { createOrder, applyCoupon as applyCouponAPI } from '../services/api';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { toast } from 'react-toastify';

const Checkout = () => {
  const { cartItems, total, clearItems } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [address, setAddress] = useState({ street: '', city: '', state: '', zip: '', country: 'Pakistan' });
  const [paymentMethod, setPaymentMethod] = useState('COD');
  const [loading, setLoading] = useState(false);
  const [couponInput, setCouponInput] = useState('');
  const [coupon, setCoupon] = useState({ code: '', discount: 0, applied: false });

  const shipping = total > 5000 ? 0 : 200;
  const tax = Math.round(total * 0.05);
  const grandTotal = Math.max(0, total + shipping + tax - coupon.discount);

  const handleApplyCoupon = async () => {
    if (!couponInput.trim()) return;
    try {
      const res = await applyCouponAPI({ code: couponInput.trim(), orderAmount: total });
      setCoupon({ code: res.data.code, discount: res.data.discount, applied: true });
      toast.success(`Coupon applied! You save PKR ${res.data.discount.toLocaleString()}`);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Invalid coupon');
      setCoupon({ code: '', discount: 0, applied: false });
    }
  };

  const removeCoupon = () => {
    setCoupon({ code: '', discount: 0, applied: false });
    setCouponInput('');
  };

  const handlePlaceOrder = async () => {
    setLoading(true);
    try {
      const orderData = {
        orderItems: cartItems.map(i => ({ product: i._id, name: i.name, image: i.images?.[0]?.url || '', price: i.discountPrice || i.price, quantity: i.quantity, seller: i.seller })),
        shippingAddress: address, paymentMethod,
        itemsPrice: total, shippingPrice: shipping, taxPrice: tax, totalPrice: grandTotal,
        couponCode: coupon.applied ? coupon.code : undefined,
      };
      const res = await createOrder(orderData);
      clearItems();
      toast.success('Order placed successfully!');
      navigate(`/orders/${res.data._id}`);
    } catch (err) { toast.error(err.response?.data?.message || 'Order failed'); }
    setLoading(false);
  };

  return (
    <div className="checkout-page">
      <div className="checkout-steps">
        <div className={`step ${step >= 1 ? 'active' : ''}`}>1. Shipping</div>
        <div className={`step ${step >= 2 ? 'active' : ''}`}>2. Payment</div>
        <div className={`step ${step >= 3 ? 'active' : ''}`}>3. Review</div>
      </div>

      <div className="checkout-layout">
        <div className="checkout-form">
          {step === 1 && (
            <div className="step-content">
              <h2>Shipping Address</h2>
              {['street', 'city', 'state', 'zip', 'country'].map(f => (
                <input key={f} placeholder={f.charAt(0).toUpperCase() + f.slice(1)} value={address[f]} onChange={e => setAddress(prev => ({ ...prev, [f]: e.target.value }))} required />
              ))}
              <button className="btn-primary" onClick={() => setStep(2)}>Continue to Payment</button>
            </div>
          )}
          {step === 2 && (
            <div className="step-content">
              <h2>Payment Method</h2>
              {['COD', 'Stripe', 'EasyPaisa', 'JazzCash'].map(m => (
                <label key={m} className="radio-label">
                  <input type="radio" value={m} checked={paymentMethod === m} onChange={() => setPaymentMethod(m)} />
                  {m === 'COD' ? 'Cash on Delivery' : m}
                </label>
              ))}
              <button className="btn-ghost" onClick={() => setStep(1)}>Back</button>
              <button className="btn-primary" onClick={() => setStep(3)}>Review Order</button>
            </div>
          )}
          {step === 3 && (
            <div className="step-content">
              <h2>Review Order</h2>
              <div className="review-address">
                <h4>Delivery to:</h4>
                <p>{address.street}, {address.city}, {address.state} {address.zip}, {address.country}</p>
              </div>
              <div className="review-payment"><h4>Payment: {paymentMethod}</h4></div>
              {cartItems.map(i => (
                <div key={i._id} className="review-item">
                  <span>{i.name} × {i.quantity}</span>
                  <span>PKR {((i.discountPrice || i.price) * i.quantity).toLocaleString()}</span>
                </div>
              ))}
              <button className="btn-ghost" onClick={() => setStep(2)}>Back</button>
              <button className="btn-primary" onClick={handlePlaceOrder} disabled={loading}>
                {loading ? 'Placing Order...' : `Place Order (PKR ${grandTotal.toLocaleString()})`}
              </button>
            </div>
          )}
        </div>

        <div className="order-summary-box">
          <h3>Order Summary</h3>
          {cartItems.map(i => (
            <div key={i._id} className="summary-item">
              <span>{i.name} × {i.quantity}</span>
              <span>PKR {((i.discountPrice || i.price) * i.quantity).toLocaleString()}</span>
            </div>
          ))}
          <hr />
          <div className="coupon-section">
            {coupon.applied ? (
              <div className="coupon-applied">
                <span>🏷️ {coupon.code} applied</span>
                <button className="btn-link" onClick={removeCoupon}>Remove</button>
              </div>
            ) : (
              <div className="coupon-input-row">
                <input
                  placeholder="Coupon code"
                  value={couponInput}
                  onChange={e => setCouponInput(e.target.value.toUpperCase())}
                />
                <button className="btn-ghost btn-sm" onClick={handleApplyCoupon}>Apply</button>
              </div>
            )}
          </div>
          <hr />
          <div className="summary-row"><span>Subtotal</span><span>PKR {total.toLocaleString()}</span></div>
          <div className="summary-row"><span>Shipping</span><span>{shipping === 0 ? 'Free' : `PKR ${shipping}`}</span></div>
          <div className="summary-row"><span>Tax (5%)</span><span>PKR {tax.toLocaleString()}</span></div>
          {coupon.applied && (
            <div className="summary-row discount"><span>Discount ({coupon.code})</span><span>- PKR {coupon.discount.toLocaleString()}</span></div>
          )}
          <div className="summary-row total"><strong>Total</strong><strong>PKR {grandTotal.toLocaleString()}</strong></div>
        </div>
      </div>
    </div>
  );
};

export default Checkout;
